    """
    Convert Euro format to USD format.
    Euro: "40.000 €", "3.494.724 €" (dots as thousands separator, € after)
    USD: "$40,000", "$3,494,724" (commas as thousands separator, $ before)
    """
    # Pattern: digits with dots as thousands separators, optional spaces, then €
    # \d{1,3} - 1 to 3 digits
    # (?:\.\d{3})+ - one or more groups of dot followed by exactly 3 digits
    # \s* - optional whitespace
    # € - euro symbol
    pattern = r'(\d{1,3}(?:\.\d{3})+)\s*€'

    def replace_match(match):
        euro_amount = match.group(1)
        # Replace dots with commas for USD format
        usd_amount = euro_amount.replace('.', ',')
        return f'${usd_amount}'

    return re.sub(pattern, replace_match, text)

