def convert_euro_to_usd_in_paragraph(para):
    """
    Convert Euro format to USD format in a paragraph.
    Works at the paragraph text level, then distributes to runs.
    """
    # Get full paragraph text
    full_text = para.text

    # Pattern: number with dots as thousands separators, optional spaces, then €
    pattern = r'(\d{1,3}(?:\.\d{3})+)\s*€'

    # Check if there's anything to convert
    if not re.search(pattern, full_text):
        return False

    # Replace all occurrences
    new_text = re.sub(pattern, lambda m: f"${m.group(1).replace('.', ',')}", full_text)

    # Clear all runs and put the new text in the first run
    if para.runs:
        para.runs[0].text = new_text
        # Clear other runs
        for run in para.runs[1:]:
            run.text = ""

    return True

