        run.font.italic = True

# Process each slide
for slide_idx, slide in enumerate(prs.slides, 1):
    for shape in slide.shapes:
        if not shape.has_text_frame:
            continue

        tf = shape.text_frame

        # SLIDE 1: Title slide - make subtitle italic
        if slide_idx == 1:
            for para in tf.paragraphs:
                para_text = para.text.strip()
                if not para_text:
                    continue
                if "Department of Education" in para_text:
                    make_paragraph_italic(para)

        # SLIDE 2: Make ALL text italic (except title)
        elif slide_idx == 2:
            if "Agenda" in tf.text:
                continue
            for para in tf.paragraphs:
                make_paragraph_italic(para)

        # SLIDE 34: Make all text italic except "Questions?" title
        elif slide_idx == 34:
            for para in tf.paragraphs:
                para_text = para.text.strip()
                if not para_text:
                    continue
                if para_text == "Questions?":
                    continue
                make_paragraph_italic(para)

        # ALL OTHER SLIDES: Make subheadings italic
        else:
            for para in tf.paragraphs:
                para_text = para.text.strip()
                if not para_text:
                    continue
                if any(para_text.startswith(k) for k in subheading_keywords):
                    make_paragraph_italic(para)

# Save
prs.save(path)
print(f"Saved: {path}")
